+func TestSimpleCacheBasicContract(t *testing.T) {
+	runGeneratedCacheProgram(t, `
+package main
+
+import (
+	"time"
+
+	cache "github.com/navidrome/navidrome/utils/cache"
+)
+
+func main() {
+	c := cache.NewSimpleCache[string]()
+
+	if err := c.Add("persist", "v1"); err != nil {
+		panic(err)
+	}
+	time.Sleep(25 * time.Millisecond)
+	if got, err := c.Get("persist"); err != nil || got != "v1" {
+		panic("expected persistent Add value")
+	}
+
+	if err := c.Add("persist", "v2"); err != nil {
+		panic(err)
+	}
+	if got, err := c.Get("persist"); err != nil || got != "v2" {
+		panic("expected replacement value")
+	}
+
+	if err := c.AddWithTTL("ttl", "v", 40*time.Millisecond); err != nil {
+		panic(err)
+	}
+	if got, err := c.Get("ttl"); err != nil || got != "v" {
+		panic("expected active TTL value")
+	}
+	time.Sleep(70 * time.Millisecond)
+	if got, err := c.Get("ttl"); err == nil || got != "" {
+		panic("expected expired TTL value to miss with zero value")
+	}
+
+	keys := c.Keys()
+	if len(keys) != 1 || keys[0] != "persist" {
+		panic("expected only active key persist")
+	}
+}
+`)
+}
+
+func TestSimpleCacheRespectsMaxActiveEntriesLimit(t *testing.T) {
+	runGeneratedCacheProgram(t, `
+package main
+
+import (
+	"fmt"
+
+	cache "github.com/navidrome/navidrome/utils/cache"
+)
+
+func main() {
+	c := cache.NewSimpleCache[string]()
+
+	for i := 0; i < 256; i++ {
+		if err := c.Add(fmt.Sprintf("k-%03d", i), "v"); err != nil {
+			panic(err)
+		}
+	}
+	if len(c.Keys()) != 256 {
+		panic("expected 256 active keys")
+	}
+	if err := c.Add("overflow", "v"); err == nil {
+		panic("expected overflow add to fail")
+	}
+	if _, err := c.Get("overflow"); err == nil {
+		panic("overflow key should not become active")
+	}
+	if len(c.Keys()) != 256 {
+		panic("expected active keys to remain unchanged")
+	}
+}
+`)
+}
+
+func TestSimpleCacheServesStaleValueOnRefreshFailure(t *testing.T) {
+	runGeneratedCacheProgram(t, `
+package main
+
+import (
+	"errors"
+	"time"
+
+	cache "github.com/navidrome/navidrome/utils/cache"
+)
+
+func main() {
+	c := cache.NewSimpleCache[string]()
+
+	if err := c.AddWithTTL("stale", "v1", 30*time.Millisecond); err != nil {
+		panic(err)
+	}
+	time.Sleep(60 * time.Millisecond)
+
+	got, err := c.GetWithLoader("stale", func(key string) (string, time.Duration, error) {
+		return "", 0, errors.New("backend down")
+	})
+	if err != nil || got != "v1" {
+		panic("expected stale fallback value")
+	}
+	if _, err := c.Get("stale"); err == nil {
+		panic("stale key should remain inactive after failed refresh")
+	}
+	for _, key := range c.Keys() {
+		if key == "stale" {
+			panic("stale key must not appear in active keys")
+		}
+	}
+}
+`)
+}
+
+func TestSimpleCacheHandlesNonPositiveLifetimes(t *testing.T) {
+	runGeneratedCacheProgram(t, `
+package main
+
+import (
+	"time"
+
+	cache "github.com/navidrome/navidrome/utils/cache"
+)
+
+func main() {
+	c := cache.NewSimpleCache[string]()
+
+	if err := c.AddWithTTL("k", "v", 0); err == nil {
+		panic("expected non-positive AddWithTTL to fail")
+	}
+	if _, err := c.Get("k"); err == nil {
+		panic("direct non-positive lifetime must not create an active entry")
+	}
+
+	got, err := c.GetWithLoader("transient", func(key string) (string, time.Duration, error) {
+		return "v", 0, nil
+	})
+	if err != nil || got != "v" {
+		panic("expected transient loader value without persistence")
+	}
+	if _, err := c.Get("transient"); err == nil {
+		panic("loader value with non-positive lifetime must remain inactive")
+	}
+	for _, key := range c.Keys() {
+		if key == "transient" {
+			panic("transient loader value must not appear in active keys")
+		}
+	}
+}
+`)
+}
