+func TestSimpleCacheSharesOutcomeAcrossOverlappingLoads(t *testing.T) {
+	runGeneratedCacheProgram(t, `
+package main
+
+import (
+	"errors"
+	"fmt"
+	"sync"
+	"sync/atomic"
+	"time"
+
+	cache "github.com/navidrome/navidrome/utils/cache"
+)
+
+func main() {
+	c := cache.NewSimpleCache[string]()
+
+	var seq int32
+	start := make(chan struct{})
+	loader := func(key string) (string, time.Duration, error) {
+		callID := atomic.AddInt32(&seq, 1)
+		<-start
+		return fmt.Sprintf("value-%d", callID), time.Second, nil
+	}
+
+	const workers = 8
+	var wg sync.WaitGroup
+	wg.Add(workers)
+	values := make([]string, workers)
+	errs := make([]error, workers)
+
+	for i := 0; i < workers; i++ {
+		i := i
+		go func() {
+			defer wg.Done()
+			values[i], errs[i] = c.GetWithLoader("shared", loader)
+		}()
+	}
+
+	time.Sleep(20 * time.Millisecond)
+	close(start)
+	wg.Wait()
+
+	first := values[0]
+	for i := 0; i < workers; i++ {
+		if errs[i] != nil || values[i] != first {
+			panic("expected one shared outcome across overlapping loads")
+		}
+	}
+
+	got, err := c.GetWithLoader("missing", func(key string) (string, time.Duration, error) {
+		return "", 0, errors.New("boom")
+	})
+	if err == nil || got != "" {
+		panic("expected loader failure when no value can be served")
+	}
+}
+`)
+}
+
+func runGeneratedCacheProgram(t *testing.T, generatedSource string) {
+	t.Helper()
+
+	root := repoRoot(t)
+	tmpDir := t.TempDir()
+
+	goMod := "module generated\n\ngo 1.22\n\nrequire github.com/navidrome/navidrome v0.0.0\n\nreplace github.com/navidrome/navidrome => " + root + "\n"
+	if err := os.WriteFile(filepath.Join(tmpDir, "go.mod"), []byte(goMod), 0o644); err != nil {
+		t.Fatalf("writing go.mod: %v", err)
+	}
+	if err := os.WriteFile(filepath.Join(tmpDir, "main.go"), []byte(strings.TrimSpace(generatedSource)+"\n"), 0o644); err != nil {
+		t.Fatalf("writing generated program: %v", err)
+	}
+
+	goBinary := "/usr/local/go/bin/go"
+	if _, err := os.Stat(goBinary); err != nil {
+		goBinary = "go"
+	}
+
+	cmd := exec.Command(goBinary, "run", "-mod=mod", ".")
+	cmd.Dir = tmpDir
+	cmd.Env = append(os.Environ(), "GOWORK=off")
+	output, err := cmd.CombinedOutput()
+	if err != nil {
+		t.Fatalf("generated cache program failed:\n%s", string(output))
+	}
+}
+
+func repoRoot(t *testing.T) string {
+	t.Helper()
+
+	wd, err := os.Getwd()
+	if err != nil {
+		t.Fatalf("getting working directory: %v", err)
+	}
+	return filepath.Clean(filepath.Join(wd, "..", ".."))
+}
